slides.code:
type Route = { path: string; auth: boolean };

// With 'as' — type is Route (widened)
const login = { path: '/login', auth: false } as Route;
login.path  // type: string (lost '/login')

// With 'satisfies' — type preserved
const login = {
  path: '/login',
  auth: false
} satisfies Route;
login.path  // type: '/login' (literal!)
